const Q_COMMERCE_2011=[{"id": "objective>Commerce>2011>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which subject are you doing?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Mathematics</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Commerce</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Computer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Physics</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The question is Commerce. Therefore,  The subject is Commerce.</div>", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : MEANING AND TYPES"}, {"id": "objective>Commerce>2011>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most important function of commerce is in </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">helping people to improve their profit </div>", "<div style=\"font-family:Cambria;font-size:17px;\">facilitating exchange among individuals and firms</div>", "<div style=\"font-family:Cambria;font-size:17px;\">assisting trade through banking and insurance </div>", "<div style=\"font-family:Cambria;font-size:17px;\">enhancing business relationship</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Commerce is crucial (important) to the life of any Nation for the following reasons: Commerce facilitates the exchange of goods and services which everyone can enjoy, regardless their location or whether the goods is produced within or outside their country. Commerce creates an awareness of the existence of goods and services through advertising.</div>", "topic": "INTRODUCTION TO COMMERCE : MEANING & SCOPE"}, {"id": "objective>Commerce>2011>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The three main classifications of occupations are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">manufacturing, industry, and services </div>", "<div style=\"font-family:Cambria;font-size:17px;\">farming, banking and trading </div>", "<div style=\"font-family:Cambria;font-size:17px;\">industry, commerce and services</div>", "<div style=\"font-family:Cambria;font-size:17px;\">construction, trade and services</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The three main classifications of occupations are industry, commerce and services. These are broad categories that can encompass a variety of job types. Industry refers to jobs in manufacturing or production, commerce refers to jobs related to trade or business, and services refer to jobs that provide a service to others.</div>", "topic": "OCCUPATION : TYPES OF OCCUPATION"}, {"id": "objective>Commerce>2011>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An oil exploration company is engaged in </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">construction occupation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">extractive occupation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">secondary production </div>", "<div style=\"font-family:Cambria;font-size:17px;\">tertiary production </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An oil exploration company is engaged in extractive occupation. Extractive occupation refers to industries involved in the extraction of raw materials from the earth. This includes mining, forestry, fishing, and oil extraction.</div>", "topic": "OCCUPATION : TYPES OF OCCUPATION"}, {"id": "objective>Commerce>2011>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Service rendered to the public is provided by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">civil servants</div>", "<div style=\"font-family:Cambria;font-size:17px;\">professionals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">domestic servants</div>", "<div style=\"font-family:Cambria;font-size:17px;\">government</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Service rendered to the public is provided by the government. This includes services like public transportation, healthcare, education, and other public utilities.</div>", "topic": "BUSINESS UNIT: PUBLIC CORPORATION : MEANING AND TYPES"}, {"id": "objective>Commerce>2011>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The creation of goods and services to satisfy human wants is referred to as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">commercialization </div>", "<div style=\"font-family:Cambria;font-size:17px;\">production </div>", "<div style=\"font-family:Cambria;font-size:17px;\">entrepreneurship </div>", "<div style=\"font-family:Cambria;font-size:17px;\">manufacturing </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is the action of making or manufacturing from components or raw materials, or the process of being so manufactured.</div>", "topic": "PRODUCTION : FACTORS OF PRODUCTION"}, {"id": "objective>Commerce>2011>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is a limitation of division of labour? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Monotony of work</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Reduction in output</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Reduction in labour force</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Decline in craftmanship</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The work can become very boring. One of the disadvantages associated with division of labor is the fact that the work that you constantly keep doing day in day out can become very monotonous and uninteresting to you. </div>", "topic": "PRODUCTION : DIVISION OF LABOUR & SPECIALISATION"}, {"id": "objective>Commerce>2011>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Resources obtained from the extractive sector that are transformed into finished products are examples of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">tertiary production </div>", "<div style=\"font-family:Cambria;font-size:17px;\">direct production </div>", "<div style=\"font-family:Cambria;font-size:17px;\">secondary production </div>", "<div style=\"font-family:Cambria;font-size:17px;\">primary production </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Secondary production refers to the process of transforming raw materials or resources obtained from the extractive sector into finished products. This is different from primary production which involves the extraction of raw materials, and tertiary production which involves the provision of services.</div>", "topic": "PRODUCTION : FACTORS OF PRODUCTION"}, {"id": "objective>Commerce>2011>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  From the diagram above, What does I stands for? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Publicity </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Home trade </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Advertising </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Aids to trade </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">I from the diagram above stands for Aids to trade.</div>", "topic": "AIDS TO TRADE: ADVERTISING : TYPES AND MEDIA"}, {"id": "objective>Commerce>2011>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An individual that links the producer with the retailer is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a wholesaler</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an entrepreneur </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a principal </div>", "<div style=\"font-family:Cambria;font-size:17px;\">an agent </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is the wholesaler. A wholesaler is an intermediary entity in the distribution channel that buys in bulk and sells to resellers rather than to consumers. In its simplest form, a distributor performs a similar role but often provides more complex services. Distributors and wholesalers often work together as channel partners.</div>", "topic": "TRADE (1) : HOME TRADE: WHOLESALE TRADE"}, {"id": "objective>Commerce>2011>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the functions of a retail is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">provision of credit facilities relations</div>", "<div style=\"font-family:Cambria;font-size:17px;\">provision of jobs for customers </div>", "<div style=\"font-family:Cambria;font-size:17px;\">breaking of bulk </div>", "<div style=\"font-family:Cambria;font-size:17px;\">financing of production activities </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">One of the functions of a retailer is the 'breaking of bulk'. This means that the retailer buys goods in large quantities from the manufacturers or wholesalers and sells them in smaller quantities to the consumers. This makes it easier for consumers to buy the quantity they need without having to buy in bulk.</div>", "topic": "TRADE (1) : HOME TRADE: RETAIL TRADE"}, {"id": "objective>Commerce>2011>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The main aim of selling directly to the consumers by manufacturers is to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">make contact with individual customers </div>", "<div style=\"font-family:Cambria;font-size:17px;\">discourage the activities of middlemen </div>", "<div style=\"font-family:Cambria;font-size:17px;\">maximizing profit margin </div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduce transportation cost  </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Manufacturers needed the validation of an established retailer to get in front of customers and make sales. But the ability to sell directly to consumers comes with benefits for both manufacturers and consumers: Manufacturers can connect directly with people who want their goods. Manufacturers can increase their profits.</div>", "topic": "ELEMENT OF MARKETING : MARKETING MIX"}, {"id": "objective>Commerce>2011>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Balance of payment problems arise if a country's</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">import is more than export </div>", "<div style=\"font-family:Cambria;font-size:17px;\">currency is devaluated </div>", "<div style=\"font-family:Cambria;font-size:17px;\">individual experts is more than visible exports</div>", "<div style=\"font-family:Cambria;font-size:17px;\">export is more than import </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The balance of payments (BOP) is the method countries use to monitor all international monetary transactions at a specific period of time. Usually, the BOP is calculated every quarter and every calendar year. Problems arise when import is more than export.</div>", "topic": "TRADE ( 2) : BALANCE OF PAYMENT"}, {"id": "objective>Commerce>2011>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The three components of a country's balance of payment are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">capital account, trade, account and business record </div>", "<div style=\"font-family:Cambria;font-size:17px;\">sales account, profit and loss account and capital account </div>", "<div style=\"font-family:Cambria;font-size:17px;\">monetary movement account, trade account and sales ledger </div>", "<div style=\"font-family:Cambria;font-size:17px;\">current account, capital account and monetary movement account </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A country's balance of payment is made up of three components: the current account, the capital account, and the financial account. The current account records a nation's transactions with the rest of the world—specifically its net trade in goods and services, its net earnings on cross-border investments, and its net transfer payments. The capital account records the net change in ownership of foreign assets. The financial account records the net change in ownership of international monetary assets.</div>", "topic": "TRADE ( 2) : BALANCE OF PAYMENT"}, {"id": "objective>Commerce>2011>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A document that indicates obligation that is transferable by delivery and endorsement is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">bill exchange </div>", "<div style=\"font-family:Cambria;font-size:17px;\">documentary evidence </div>", "<div style=\"font-family:Cambria;font-size:17px;\">negotiation instrument </div>", "<div style=\"font-family:Cambria;font-size:17px;\">bill of lading </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A negotiation instrument is a document that gives the holder the right to demand payment from the maker of the instrument. Negotiation instruments are transferable by delivery and endorsement. This means that the holder of the instrument can transfer their right to payment to another person by delivering the instrument to them and endorsing it. <br/>  <br/> There are two main types of negotiation instruments: bills of exchange and promissory notes. <br/> -  A bill of exchange is a written order from one person (the drawer) to another person (the drawee) to pay a third person (the payee) a certain sum of money on demand or at a future date. <br/> -  A promissory note is a written promise from one person (the maker) to pay a certain sum of money to another person (the payee) on demand or at a future date. <br/>  <br/> Both bills of exchange and promissory notes can be used as negotiation instruments. When a negotiation instrument is transferred by delivery and endorsement, the endorser becomes liable for the payment of the instrument to the holder.</div>", "topic": "TRADE ( 2) : DOCMENT USED IN INTERNATION TRADE"}, {"id": "objective>Commerce>2011>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The document which can be exchanged for a bill of lading is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">mate receipt </div>", "<div style=\"font-family:Cambria;font-size:17px;\">export invoice </div>", "<div style=\"font-family:Cambria;font-size:17px;\">ship report </div>", "<div style=\"font-family:Cambria;font-size:17px;\">freight note </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The mate's receipt or receipts collected by the shipper or his representative and later exchanged for a bill of lading, which should incorporate any qualifications or conditions inserted into the mate's receipt.</div>", "topic": "TRADE ( 2) : DOCMENT USED IN INTERNATION TRADE"}, {"id": "objective>Commerce>2011>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The price quoted which include the cost of insurance, freight and all delivery charges to the importer's warehouse is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Franco</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Free of Board</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Free on Rail </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Free alongside ship</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Franco means free delivery. It is a term used to describe a sale in which the seller pays for part of the transport charges, that is, sales in which goods are delivered free to a certain point.</div>", "topic": "PURCHASES AND SALES OF GOODS : TERMS OF TRADE"}, {"id": "objective>Commerce>2011>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The purchase of goods under the CWO system of payment implies that </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">payment must be paid on delivery </div>", "<div style=\"font-family:Cambria;font-size:17px;\">payment must be made within few days </div>", "<div style=\"font-family:Cambria;font-size:17px;\">cash must be paid on the spot </div>", "<div style=\"font-family:Cambria;font-size:17px;\">money must be enclosed when ordering </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">CWO stands for Cash With Order. This means that payment must be made at the time of placing the order. Therefore, the correct answer is 'money must be enclosed when ordering'.</div>", "topic": "PURCHASES AND SALES OF GOODS : TERMS OF PAYMENT"}, {"id": "objective>Commerce>2011>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most effective but limited medium of advertising in Nigeria is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">television </div>", "<div style=\"font-family:Cambria;font-size:17px;\">newspaper </div>", "<div style=\"font-family:Cambria;font-size:17px;\">radio </div>", "<div style=\"font-family:Cambria;font-size:17px;\">billboard </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">the cons of tv advert are: <br/> - it is expenses <br/> -non- targeted audience <br/> - less flexibility <br/> - target core audience</div>", "topic": "AIDS TO TRADE: ADVERTISING : TYPES AND MEDIA"}, {"id": "objective>Commerce>2011>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A cheque that has been drawn but not presented for payment can still be honoured </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">after 9 months</div>", "<div style=\"font-family:Cambria;font-size:17px;\">within 9 months</div>", "<div style=\"font-family:Cambria;font-size:17px;\">after 6 months</div>", "<div style=\"font-family:Cambria;font-size:17px;\">within 6 months</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">This means that the cheque can be presented for payment anytime within 6 months of the date it was issued. After this period, it may be considered stale-dated, and the bank may have the discretion to refuse payment. However, specific banking regulations and policies may vary, so it's essential to check with the relevant bank or financial institution for their specific rules regarding stale-dated cheques.</div>", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLEGES"}, {"id": "objective>Commerce>2011>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major source of income to commercial banks is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">deposits </div>", "<div style=\"font-family:Cambria;font-size:17px;\">interest </div>", "<div style=\"font-family:Cambria;font-size:17px;\">overdraft </div>", "<div style=\"font-family:Cambria;font-size:17px;\">loans</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The major source of income for commercial banks is the interest they earn from the loans they give out to customers. While deposits, overdrafts, and loans are all important aspects of a bank's operations, it is the interest charged on these loans that generates the most income. Therefore, the correct answer is 'interest'.</div>", "topic": "AIDS TO TRADE: BANKING : SERVICES & CHALLEGES"}, {"id": "objective>Commerce>2011>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An ancillary to trade that easily links suppliers with consumers is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">banking </div>", "<div style=\"font-family:Cambria;font-size:17px;\">communication </div>", "<div style=\"font-family:Cambria;font-size:17px;\">transportation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tourism </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Communication is the means of sending and receiving information from one place to another. Suppliers and customers can be easily linked together through communication services e.g telephone, telex, internet/e-mail etc. The development of telecommunication systems has also eased and hastened contacts between people within commercial centres and all over the world.</div>", "topic": "AIDS TO TRADE: COMMUNICATION : TYPES"}, {"id": "objective>Commerce>2011>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Mr Lawal insured his warehouse against burglary but it was later gutted by fire. This implies that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Mr. Lawal is liable only for half of estimated loss </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the insurer should make a consolation payment for the loss </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the loss should be borne by Mr Lawal </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the loss should be borne by the insurer </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The principle of insurance states that the insurance policy must cover the risk that caused the loss. In this case, Mr. Lawal insured his warehouse against burglary, not fire. Therefore, the loss caused by the fire is not covered by the insurance policy and should be borne by Mr. Lawal.</div>", "topic": "AIDS TO TRADE: INSURANCE : PRINCIPLES"}, {"id": "objective>Commerce>2011>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The agreement of insurers to spread risk among themselves is a major feature of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">life assurance  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">underwriter </div>", "<div style=\"font-family:Cambria;font-size:17px;\">marine insurance </div>", "<div style=\"font-family:Cambria;font-size:17px;\">reinsurance </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Reinsurance is insurance that is purchased by an insurance company (the \"ceding company\" or \"cedent\" or \"cedant\" under the arrangement) from one or more other insurance companies (the \"reinsurer\") directly or through a broker as a means of risk management.</div>", "topic": "AIDS TO TRADE: INSURANCE : TYPES"}, {"id": "objective>Commerce>2011>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Inbound tourism occurs when </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">residents of a country travel to other countries </div>", "<div style=\"font-family:Cambria;font-size:17px;\">non-residents of a country travel within it </div>", "<div style=\"font-family:Cambria;font-size:17px;\">residents of a country travel within it </div>", "<div style=\"font-family:Cambria;font-size:17px;\">non-residents of a country travel to other countries </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Inbound tourism refers to the activities of a visitor from outside of the country of reference and who stays at least one night in the country. Therefore, it occurs when non-residents of a country travel within it.</div>", "topic": "AIDS TO TRADE: TOURISM : TYPES & IMPORTANCE"}, {"id": "objective>Commerce>2011>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the major disadvantages of pipeline transportation is its</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">limitation in scope </div>", "<div style=\"font-family:Cambria;font-size:17px;\">vulnerability to climate changes </div>", "<div style=\"font-family:Cambria;font-size:17px;\">high maintenance cost </div>", "<div style=\"font-family:Cambria;font-size:17px;\">high cost of construction </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Pipeline transportation is limited in scope which is the main disadvantage because it is only suitable for the transportation of certain types of goods, such as oil and gas. It cannot be used to transport a wide variety of goods, unlike other forms of transportation such as road, rail, or air. <br/>  <br/> The other disadvantages of pipeline transportation are: <br/> - prone to leakages and authorised tapping <br/> - high cost of construction <br/> - easily damaged <br/> - it is vulnerable to climatic change</div>", "topic": "AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION"}, {"id": "objective>Commerce>2011>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The business organization that can effectively combine management with control is  </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sole proprietorship</div>", "<div style=\"font-family:Cambria;font-size:17px;\">public limited liability company </div>", "<div style=\"font-family:Cambria;font-size:17px;\">co-operative society </div>", "<div style=\"font-family:Cambria;font-size:17px;\">private limited company </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sole proprietorship is unofficial because it is not subject to federal or state regulation, also it is relatively simple to manage and control. In this type of business, one person that is the proprietor provides all the capital required to carry on the business</div>", "topic": "BUSINESS UNIT: LIMITED LIABILITY COMPANIES : FEATURES AND IMPORTANCE"}, {"id": "objective>Commerce>2011>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When two or more companies agree to execute a project too large for one to handle, this is referred to as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a cartel </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a merger </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a consortium </div>", "<div style=\"font-family:Cambria;font-size:17px;\">an amalgamation </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A consortium is an association of two or more individuals, companies, organizations or governments (or any combination of these entities) with the objective of participating in a common activity or pooling their resources for achieving a common goal.</div>", "topic": "BUSINESS UNIT: MERGER : MEANING AND TYPES OF MERGER"}, {"id": "objective>Commerce>2011>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the event of voluntary liquidation, the appointment of a liquidator is the responsibility of the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">creditors</div>", "<div style=\"font-family:Cambria;font-size:17px;\">promoters</div>", "<div style=\"font-family:Cambria;font-size:17px;\">court</div>", "<div style=\"font-family:Cambria;font-size:17px;\">directors</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the event of voluntary liquidation, the appointment of a liquidator is the responsibility of the directors of the company. Voluntary liquidation is a self-imposed wind up and dissolution of a company that has been approved by shareholders. Such a decision will happen once a company's leadership decides that the company has no reason to continue operating.</div>", "topic": "BUSINESS UNIT: MERGER : DISSOLUTION AND LIQUIDATION"}, {"id": "objective>Commerce>2011>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A source of business financing which involves pledging of a specific asset is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">mortgage </div>", "<div style=\"font-family:Cambria;font-size:17px;\">debentures </div>", "<div style=\"font-family:Cambria;font-size:17px;\">loan</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bond </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A mortgage, which is a special type of loan for buying property where monthly payments are spread over a number of years.</div>", "topic": "FINANCING BUSINESS : SOURCE OF FINANCE"}, {"id": "objective>Commerce>2011>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An example of trade association is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">NLC</div>", "<div style=\"font-family:Cambria;font-size:17px;\">NURTW</div>", "<div style=\"font-family:Cambria;font-size:17px;\">NULGE</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ALGON</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">NLC, NURTW, and NULGE are trade unions, not trade associations. Trade unions are organizations that represent workers in negotiations with employers. Trade associations, on the other hand, are organizations that represent businesses in a particular industry. <br/>  <br/> ALGON is the Association of Local Governments of Nigeria. It is a trade association that represents the interests of local governments in Nigeria. <br/>  <br/> Trade associations are organizations formed by businesses or entities in a particular industry or sector to promote their common interests, advocate for industry-specific policies, and provide support and resources to their members. ALGON represents local governments in Nigeria, making it a trade association for local government authorities.</div>", "topic": "TRADE ASSOCIATION : MEANING & FUNCTIONS"}, {"id": "objective>Commerce>2011>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A broker is an agent who links a potential investor with</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">other members of the exchange who want to trade </div>", "<div style=\"font-family:Cambria;font-size:17px;\">government official on the exchange </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a quoted company </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a shareholder who wants to register a company </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A broker is an agent who links a potential investor with other members of the exchange who want to trade. A broker acts as an intermediary between buyers and sellers in a financial market, facilitating transactions between them.</div>", "topic": "STOCK EXCHANGE : PROCEDURES OF TRANSACTIONS"}, {"id": "objective>Commerce>2011>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Second-Tier securities market differs from the First-Tier Securities Market in that the former is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">regulated by SEC</div>", "<div style=\"font-family:Cambria;font-size:17px;\">regulated by the NIPC</div>", "<div style=\"font-family:Cambria;font-size:17px;\">less restricted </div>", "<div style=\"font-family:Cambria;font-size:17px;\">highly restricted </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Second-Tier Securities Market is less restricted compared to the First-Tier Securities Market. The Second-Tier Securities Market is designed for smaller companies, with less stringent listing requirements, making it less restricted.</div>", "topic": "STOCK EXCHANGE : SECOND- TIER SECURITIES MARKET"}, {"id": "objective>Commerce>2011>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A communication process providing information for decision-making in an organization is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Transmission Control Protocol </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Information Retrieval System </div>", "<div style=\"font-family:Cambria;font-size:17px;\">File transfer Protocol </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Management of Information System  </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Management of Information System (MIS) is a communication process providing information for decision-making in an organization. MIS is a computer-based system that provides managers with the tools to organize, evaluate and efficiently manage departments within an organization.</div>", "topic": "AIDS TO TRADE: COMMUNICATION : PROCESS & PROCEDURE"}, {"id": "objective>Commerce>2011>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The managerial ability of a supervisor in an organization may be under utilized if the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">span of control is wide </div>", "<div style=\"font-family:Cambria;font-size:17px;\">span of control is narrow</div>", "<div style=\"font-family:Cambria;font-size:17px;\">morale of the supervised is low</div>", "<div style=\"font-family:Cambria;font-size:17px;\">morale of the supervised is high </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The span of control refers to the number of subordinates that a manager or supervisor can efficiently and effectively direct. If the span of control is too narrow, it means the manager supervises few subordinates. This can lead to underutilization because the managers capacity to manage more subordinates is not fully utilized. </div>", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : ORGANIZATIONAL STRUCTURE"}, {"id": "objective>Commerce>2011>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The arrangement and interrelationship of the various components and positions of a business is referred to as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">clarity of objective </div>", "<div style=\"font-family:Cambria;font-size:17px;\">unity of direction </div>", "<div style=\"font-family:Cambria;font-size:17px;\">line structure </div>", "<div style=\"font-family:Cambria;font-size:17px;\">organizational structure </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Organizational structure shows the functional relationship that exists among the employees and the various departments within organizations. </div>", "topic": "ELEMENTS OF BUSINESS MANAGEMENT : ORGANIZATIONAL STRUCTURE"}, {"id": "objective>Commerce>2011>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The variety of goods and services which company offers for sale is its </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">promotion mix </div>", "<div style=\"font-family:Cambria;font-size:17px;\">price mix </div>", "<div style=\"font-family:Cambria;font-size:17px;\">product mix </div>", "<div style=\"font-family:Cambria;font-size:17px;\">place mix </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A product mix is the total number of product lines and individual products or services offered by a company. Additionally referred to as product assortment or product portfolio. Product mixes vary from company to company. Some have multiple product lines with lots of products in each line.</div>", "topic": "ELEMENT OF MARKETING : MARKETING MIX"}, {"id": "objective>Commerce>2011>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Activities undertaken to create awareness for goods by conducting contest is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">consumerism </div>", "<div style=\"font-family:Cambria;font-size:17px;\">sales promotion </div>", "<div style=\"font-family:Cambria;font-size:17px;\">marketing mix </div>", "<div style=\"font-family:Cambria;font-size:17px;\">marketing concept </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sales promotion is the process of persuading a potential customer to buy the product. Sales promotion is designed to be used as a short-term tactic to boost sales – it is rarely suitable as a method of building long-term customer loyalty.</div>", "topic": "ELEMENT OF MARKETING : PUBLIC RELATION & CUSTOMER SERVICE"}, {"id": "objective>Commerce>2011>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The slogan, a wonderful world, used by a communication network is a form of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">persuasive advertising </div>", "<div style=\"font-family:Cambria;font-size:17px;\">publicity </div>", "<div style=\"font-family:Cambria;font-size:17px;\">packaging </div>", "<div style=\"font-family:Cambria;font-size:17px;\">product differentiation </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Slogan works best to display the real perspective for any business, this way it can attract the targeted audience easily and can also connect with them emotionally.A slogan is a memorable motto or phrase used in a clan, political, commercial, religious, and other context as a repetitive expression of an idea or purpose, with the goal of persuading members of the public or a more defined target group.  It is a form of persuasive advertising. It is a type of product promotion that attempts to influence a consumer in favor of a purchasing particular good or service.</div>", "topic": "AIDS TO TRADE: ADVERTISING : TYPES AND MEDIA"}, {"id": "objective>Commerce>2011>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">To make a simple contract valid, the intention must be </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">legal and binding </div>", "<div style=\"font-family:Cambria;font-size:17px;\">legal and attractive </div>", "<div style=\"font-family:Cambria;font-size:17px;\">legal and harmonious </div>", "<div style=\"font-family:Cambria;font-size:17px;\">legal and written </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">For a contract to be valid, everyone entering the contract must show clear intention to begin a formal agreement and accept the terms as legally binding. </div>", "topic": "LEGAL ASPECT OF BUSINESS: CONTRACT : ELEMENT OF A VALID CONTRACT"}, {"id": "objective>Commerce>2011>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major parties to an agency relationship are the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">baile and the bailer </div>", "<div style=\"font-family:Cambria;font-size:17px;\">principal and the agent </div>", "<div style=\"font-family:Cambria;font-size:17px;\">shareholder and the creditor  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">principal and the creditor </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In an agency relationship, the two major parties involved are the principal and the agent. The principal is the person who authorizes the agent to act on their behalf, while the agent is the person who has the authority to act for the principal. The agent can make legal agreements with third parties that the principal must abide by.</div>", "topic": "LEGAL ASPECT OF BUSINESS: CONTRACT : ELEMENT OF A VALID CONTRACT"}, {"id": "objective>Commerce>2011>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the obligations of an employer to an employee is to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">award scholarship to his children </div>", "<div style=\"font-family:Cambria;font-size:17px;\">terminate his appointment without prior notice </div>", "<div style=\"font-family:Cambria;font-size:17px;\">indemnify him against industries caused through negligence </div>", "<div style=\"font-family:Cambria;font-size:17px;\">indemnify him against liabilities incurred on duty </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The duties of the employer are: <br/> - duty to pay salaries <br/> - duty to provide work <br/> - duty to indemnify the employee i.e it is the duty of the employer to indemnify the employee for any liability to a third party or for expenses incurred in the discharge of his duty to his employer or injury suffered due to the negligence of a co-employee. <br/> - duty to furnish references <br/> - duty to ensure safety of the employee at work</div>", "topic": "LEGAL ASPECT OF BUSINESS: CONTRACT OF EMPLOYMENT : DUTIES OF THE EMPLOYEE AND EMPLOYER"}, {"id": "objective>Commerce>2011>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The body charged with the responsibility of regulating foods and drugs in Nigeria is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">NDLEA</div>", "<div style=\"font-family:Cambria;font-size:17px;\">NAFDAC</div>", "<div style=\"font-family:Cambria;font-size:17px;\">CAC</div>", "<div style=\"font-family:Cambria;font-size:17px;\">SON</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">NAFDAC means The National Agency for Food and Drug Administration and Control (NAFDAC). It is a Nigerian government agency under the Federal Ministry of Health.</div>", "topic": "LEGAL ASPECT OF BUSINESS: GOVERNMENT REGULATION : REGULATORY AGENCIES"}, {"id": "objective>Commerce>2011>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The physical components of a computer operating system is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">hardware</div>", "<div style=\"font-family:Cambria;font-size:17px;\">software</div>", "<div style=\"font-family:Cambria;font-size:17px;\">compact disk</div>", "<div style=\"font-family:Cambria;font-size:17px;\">system unit </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Computer hardware includes the physical parts of a computer, such as the case, central processing unit (CPU), monitor, mouse, keyboard, computer data storage, graphics card, sound card, speakers and motherboard.</div>", "topic": "INFORMATIONAND COMMUNICATION TECHNOLOGY (ICT) : TYPES OF COMPUTER AND FUNCTIONS"}, {"id": "objective>Commerce>2011>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An example of a computer operating system is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The Word Perfect </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Microsoft Word 2000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Windows 2000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The pagemaker </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Examples of operating systems are Disk Operating System (DOS), Windows, MacOS, and UNIX Windows 2000.</div>", "topic": "INFORMATIONAND COMMUNICATION TECHNOLOGY (ICT) : ACTIVITIES IN COMPUTER"}, {"id": "objective>Commerce>2011>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Intranet differs from extranet in that the former </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">can generally be accessed by the public  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">is restricted to employees of an organization </div>", "<div style=\"font-family:Cambria;font-size:17px;\">requires internet protocols</div>", "<div style=\"font-family:Cambria;font-size:17px;\">require a modem before it could be used </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Intranet: A private network based on the internet protocol for sharing information, collaboration tools, operational systems and other computing services within an organization, usually to the exclusion of access by outsiders. It is restricted to employees of the organization. <br/>  <br/> Extranet: A controlled private network that allows access to partners, vendors and supplier or an authorized set of customers. It is for information sharing and restricted to those users who have login credentials. <br/> </div>", "topic": "INFORMATIONAND COMMUNICATION TECHNOLOGY (ICT) : MERITS & DEMERIT"}, {"id": "objective>Commerce>2011>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A software application which enables a user to display and interact with text, images and videos is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">internet protocol </div>", "<div style=\"font-family:Cambria;font-size:17px;\">corel draw</div>", "<div style=\"font-family:Cambria;font-size:17px;\">web browser </div>", "<div style=\"font-family:Cambria;font-size:17px;\">web server </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A web browser is a software application that allows a user to display and interact with text, images, and other information typically located on a web page at a website on the World Wide Web or a local area network. Internet protocol is a set of rules governing the format of data sent over the Internet or other network. Corel Draw is a vector graphics editor, not a software for interacting with text, images, and videos. A web server is a computer system that processes requests via HTTP, the basic network protocol used to distribute information on the World Wide Web.</div>", "topic": "INFORMATIONAND COMMUNICATION TECHNOLOGY (ICT) : ACTIVITIES IN COMPUTER"}, {"id": "objective>Commerce>2011>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A predominant mark-up language for web pages is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">HTTP</div>", "<div style=\"font-family:Cambria;font-size:17px;\">HTML</div>", "<div style=\"font-family:Cambria;font-size:17px;\">TCP</div>", "<div style=\"font-family:Cambria;font-size:17px;\">IP</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">HTML (HyperText Markup Language) is the standard markup language for documents designed to be displayed in a web browser. It can be assisted by technologies such as Cascading Style Sheets (CSS) and scripting languages such as JavaScript. HTTP (Hypertext Transfer Protocol) is the protocol used for transmitting hypertext via the internet. TCP (Transmission Control Protocol) is one of the main protocols in IP networks, while IP (Internet Protocol) is the principal communications protocol in the Internet protocol suite for relaying datagrams across network boundaries.</div>", "topic": "INFORMATIONAND COMMUNICATION TECHNOLOGY (ICT) : TERMS IN COMPUTER"}, {"id": "objective>Commerce>2011>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The symbol @ in an internet mail address is used to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">link the user with other internet users </div>", "<div style=\"font-family:Cambria;font-size:17px;\">locate the addresses of internet users </div>", "<div style=\"font-family:Cambria;font-size:17px;\">link the user with the machine </div>", "<div style=\"font-family:Cambria;font-size:17px;\">separate the user name from the machine name</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The symbol @ in an internet mail address is used to separate the user name from the machine name. It is a divider in email addresses, separating the recipient's name from the domain name of the email provider. The other options are incorrect as the @ symbol does not link the user with other internet users, locate the addresses of internet users, or link the user with the machine.</div>", "topic": "INFORMATIONAND COMMUNICATION TECHNOLOGY (ICT) : TERMS IN COMPUTER"}, {"id": "objective>Commerce>2011>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A business organization is said to be socially responsible when it </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">rewards its staff for long-term service </div>", "<div style=\"font-family:Cambria;font-size:17px;\">offers discounts to customers </div>", "<div style=\"font-family:Cambria;font-size:17px;\">invites the public to its annual general meetings </div>", "<div style=\"font-family:Cambria;font-size:17px;\">gets involved in issues relating to the society </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Social responsibility is an ethical framework which suggests that an entity, be it an organization or individual, has an obligation to act for the benefit of society at large.</div>", "topic": "BUSINESS ENVIRONMENT AND SOCIAL RESPONSIBILITY : MEANING AND TYPES"}];
